import{d as a}from"./app.388479f4.js";import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";const r={},h=a('<h1 id="mysql\u4E8B\u52A1" tabindex="-1"><a class="header-anchor" href="#mysql\u4E8B\u52A1" aria-hidden="true">#</a> MySQL\u4E8B\u52A1</h1><h2 id="\u4EC0\u4E48\u662F\u4E8B\u52A1" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F\u4E8B\u52A1" aria-hidden="true">#</a> \u4EC0\u4E48\u662F\u4E8B\u52A1\uFF1F</h2><p>\u4E00\u7EC4\u64CD\u4F5C\uFF0C\u8981\u4E48\u90FD\u6267\u884C\uFF0C\u8981\u4E48\u90FD\u4E0D\u6267\u884C\u3002</p><p>\u7ECF\u5178\u4F8B\u5B50\uFF1A\u94F6\u884C\u8F6C\u8D26\uFF0CA\u7ED9B\u8F6C\u8D26\u3002\u8981\u4ECEA\u7684\u8D26\u6237\u6263\u9664100\u5143\uFF0C\u5728\u7ED9B\u7684\u8D26\u6237\u589E\u52A0100\u5143\u3002\u4E8B\u52A1\u5C31\u662F\u4E3A\u4E86\u4FDD\u8BC1\u8FD9\u4E2A\u8FC7\u7A0B\u7684\u987A\u5229\u5B8C\u6210\uFF0C \u8981\u4E48\u90FD\u6210\u529F\u8981\u4E48\u90FD\u5931\u8D25\u3002</p><h2 id="\u4E8B\u52A1\u7684\u7279\u6027-caid" tabindex="-1"><a class="header-anchor" href="#\u4E8B\u52A1\u7684\u7279\u6027-caid" aria-hidden="true">#</a> \u4E8B\u52A1\u7684\u7279\u6027\uFF08CAID\uFF09</h2><h3 id="\u539F\u5B50\u6027" tabindex="-1"><a class="header-anchor" href="#\u539F\u5B50\u6027" aria-hidden="true">#</a> \u539F\u5B50\u6027</h3><p>\u4E8B\u52A1\u662F\u6700\u5C0F\u7684\u6267\u884C\u5355\u4F4D\uFF0C\u4E0D\u5141\u8BB8\u5206\u5272\u3002\u4E8B\u52A1\u7684\u539F\u5B50\u6027\u786E\u4FDD\u52A8\u4F5C\u8981\u4E48\u5168\u90E8\u5B8C\u6210\uFF0C\u8981\u4E48\u5B8C\u5168\u4E0D\u8D77\u4F5C\u7528\uFF1B</p><h3 id="\u4E00\u81F4\u6027" tabindex="-1"><a class="header-anchor" href="#\u4E00\u81F4\u6027" aria-hidden="true">#</a> \u4E00\u81F4\u6027</h3><p>\u6267\u884C\u4E8B\u52A1\u524D\u540E\uFF0C\u6570\u636E\u4FDD\u6301\u4E00\u81F4\uFF0C\u4F8B\u5982\u8F6C\u8D26\u4E1A\u52A1\u4E2D\uFF0C\u65E0\u8BBA\u4E8B\u52A1\u662F\u5426\u6210\u529F\uFF0C\u8F6C\u8D26\u8005\u548C\u6536\u6B3E\u4EBA\u7684\u603B\u989D\u5E94\u8BE5\u662F\u4E0D\u53D8\u7684\uFF1B</p><h3 id="\u9694\u79BB\u6027" tabindex="-1"><a class="header-anchor" href="#\u9694\u79BB\u6027" aria-hidden="true">#</a> \u9694\u79BB\u6027</h3><p>\u5E76\u53D1\u8BBF\u95EE\u6570\u636E\u5E93\u65F6\uFF0C\u4E00\u4E2A\u7528\u6237\u7684\u4E8B\u52A1\u4E0D\u88AB\u5176\u4ED6\u4E8B\u52A1\u6240\u5E72\u6270\uFF0C\u5404\u5E76\u53D1\u4E8B\u52A1\u4E4B\u95F4\u6570\u636E\u5E93\u662F\u72EC\u7ACB\u7684\uFF1B</p><h3 id="\u6301\u4E45\u6027" tabindex="-1"><a class="header-anchor" href="#\u6301\u4E45\u6027" aria-hidden="true">#</a> \u6301\u4E45\u6027</h3><p>\u4E00\u4E2A\u4E8B\u52A1\u88AB\u63D0\u4EA4\u4E4B\u540E\u3002\u5B83\u5BF9\u6570\u636E\u5E93\u4E2D\u6570\u636E\u7684\u6539\u53D8\u662F\u6301\u4E45\u7684\uFF0C\u5373\u4F7F\u6570\u636E\u5E93\u53D1\u751F\u6545\u969C\u4E5F\u4E0D\u5E94\u8BE5\u5BF9\u5176\u6709\u4EFB\u4F55\u5F71\u54CD\u3002</p><h2 id="\u5E76\u53D1\u4E8B\u52A1\u5E26\u6765\u7684\u95EE\u9898" tabindex="-1"><a class="header-anchor" href="#\u5E76\u53D1\u4E8B\u52A1\u5E26\u6765\u7684\u95EE\u9898" aria-hidden="true">#</a> \u5E76\u53D1\u4E8B\u52A1\u5E26\u6765\u7684\u95EE\u9898</h2><h3 id="\u810F\u8BFB-dirty-read" tabindex="-1"><a class="header-anchor" href="#\u810F\u8BFB-dirty-read" aria-hidden="true">#</a> \u810F\u8BFB\uFF08Dirty read\uFF09</h3><p>\u4E00\u4E2A\u4E8B\u52A1\u5BF9\u6570\u636E\u8FDB\u884C\u4FEE\u6539\u5355\u4F4D\u63D0\u4EA4\uFF0C\u8FD9\u65F6\u53E6\u5916\u4E00\u4E2A\u4E8B\u52A1\u4E5F\u5BF9\u8FD9\u4E2A\u6570\u636E\u8FDB\u884C\u8BFB\u53D6\uFF0C\u5E76\u4F7F\u7528\u4E86\u8FD9\u4E2A\u6570\u636E\u3002\u56E0\u4E3A\u8FD9\u4E2A\u6570\u636E\u662F\u8FD8\u6CA1\u6709\u63D0\u4EA4\u7684\u6570\u636E\uFF0C \u90A3\u4E48\u53E6\u5916\u4E00\u4E2A\u4E8B\u52A1\u8BFB\u5230\u7684\u8FD9\u4E2A\u6570\u636E\u662F\u201C\u810F\u6570\u636E\u201D\uFF0C\u4F9D\u636E\u201C\u810F\u6570\u636E\u201D\u6240\u505A\u7684\u64CD\u4F5C\u53EF\u80FD\u662F\u4E0D\u6B63\u786E\u7684\u3002</p><h3 id="\u4E22\u5931\u4FEE\u6539-lost-to-modify" tabindex="-1"><a class="header-anchor" href="#\u4E22\u5931\u4FEE\u6539-lost-to-modify" aria-hidden="true">#</a> \u4E22\u5931\u4FEE\u6539\uFF08Lost to modify\uFF09</h3><p>\u6307\u5728\u4E00\u4E2A\u4E8B\u52A1\u8BFB\u53D6\u4E00\u4E2A\u6570\u636E\u65F6\uFF0C\u53E6\u5916\u4E00\u4E2A\u4E8B\u52A1\u4E5F\u8BBF\u95EE\u4E86\u8BE5\u6570\u636E\uFF0C\u90A3\u4E48\u5728\u7B2C\u4E00\u4E2A\u4E8B\u52A1\u4E2D\u4FEE\u6539\u4E86\u8FD9\u4E2A\u6570\u636E\u540E\uFF0C\u7B2C\u4E8C\u4E2A\u4E8B\u52A1\u4E5F\u4FEE\u6539\u4E86\u8FD9\u4E2A\u6570\u636E\u3002 \u8FD9\u6837\u7B2C\u4E00\u4E2A\u4E8B\u52A1\u5185\u7684\u4FEE\u6539\u7ED3\u679C\u5C31\u88AB\u4E22\u5931\uFF0C\u56E0\u6B64\u79F0\u4E3A\u4E22\u5931\u4FEE\u6539\u3002</p><p>\u4F8B\u5982\uFF1A\u4E8B\u52A1 1 \u8BFB\u53D6\u67D0\u8868\u4E2D\u7684\u6570\u636E A=20\uFF0C\u4E8B\u52A1 2 \u4E5F\u8BFB\u53D6 A=20\uFF0C\u4E8B\u52A1 1 \u4FEE\u6539 A=A-1\uFF0C\u4E8B\u52A1 2 \u4E5F\u4FEE\u6539 A=A-1\uFF0C\u6700\u7EC8\u7ED3\u679C A=19\uFF0C\u4E8B\u52A1 1 \u7684\u4FEE\u6539\u88AB\u4E22\u5931\u3002</p><h3 id="\u4E0D\u53EF\u91CD\u590D\u8BFB" tabindex="-1"><a class="header-anchor" href="#\u4E0D\u53EF\u91CD\u590D\u8BFB" aria-hidden="true">#</a> \u4E0D\u53EF\u91CD\u590D\u8BFB</h3><p>\u6307\u5728\u4E00\u4E2A\u4E8B\u52A1\u5185\u591A\u6B21\u8BFB\u540C\u4E00\u6570\u636E\u3002\u5728\u8FD9\u4E2A\u4E8B\u52A1\u8FD8\u6CA1\u6709\u7ED3\u675F\u65F6\uFF0C\u53E6\u4E00\u4E2A\u4E8B\u52A1\u4E5F\u8BBF\u95EE\u8BE5\u6570\u636E\u3002 \u90A3\u4E48\uFF0C\u5728\u7B2C\u4E00\u4E2A\u4E8B\u52A1\u4E2D\u7684\u4E24\u6B21\u8BFB\u6570\u636E\u4E4B\u95F4\uFF0C\u7531\u4E8E\u7B2C\u4E8C\u4E2A\u4E8B\u52A1\u7684\u4FEE\u6539\u5BFC\u81F4\u7B2C\u4E00\u4E2A\u4E8B\u52A1\u4E24\u6B21\u8BFB\u53D6\u7684\u6570\u636E\u53EF\u80FD\u4E0D\u592A\u4E00\u6837\u3002 \u8FD9\u5C31\u53D1\u751F\u4E86\u5728\u4E00\u4E2A\u4E8B\u52A1\u5185\u4E24\u6B21\u8BFB\u5230\u7684\u6570\u636E\u662F\u4E0D\u4E00\u6837\u7684\u60C5\u51B5\uFF0C\u56E0\u6B64\u79F0\u4E3A\u4E0D\u53EF\u91CD\u590D\u8BFB\u3002</p><h3 id="\u5E7B\u8BFB" tabindex="-1"><a class="header-anchor" href="#\u5E7B\u8BFB" aria-hidden="true">#</a> \u5E7B\u8BFB</h3><p>\u5E7B\u8BFB\u4E0E\u4E0D\u53EF\u91CD\u590D\u8BFB\u7C7B\u4F3C\u3002\u5B83\u53D1\u751F\u5728\u4E00\u4E2A\u4E8B\u52A1\uFF08T1\uFF09\u8BFB\u53D6\u4E86\u51E0\u884C\u6570\u636E\uFF0C\u63A5\u7740\u53E6\u4E00\u4E2A\u5E76\u53D1\u4E8B\u52A1\uFF08T2\uFF09\u63D2\u5165\u4E86\u4E00\u4E9B\u6570\u636E\u65F6\u3002 \u5728\u968F\u540E\u7684\u67E5\u8BE2\u4E2D\uFF0C\u7B2C\u4E00\u4E2A\u4E8B\u52A1\uFF08T1\uFF09\u5C31\u4F1A\u53D1\u73B0\u591A\u4E86\u4E00\u4E9B\u539F\u672C\u4E0D\u5B58\u5728\u7684\u8BB0\u5F55\uFF0C\u5C31\u597D\u50CF\u53D1\u751F\u4E86\u5E7B\u89C9\u4E00\u6837\uFF0C\u6240\u4EE5\u79F0\u4E3A\u5E7B\u8BFB\u3002</p><blockquote><p>\u4E0D\u53EF\u91CD\u590D\u8BFB\u548C\u5E7B\u8BFB\u7684\u533A\u522B\uFF1A</p><p>\u4E0D\u53EF\u91CD\u590D\u8BFB\u7684\u91CD\u70B9\u662F\u4FEE\u6539\uFF0C\u5E7B\u8BFB\u7684\u91CD\u70B9\u5728\u4E8E\u65B0\u589E\u6216\u8005\u5220\u9664\u3002</p></blockquote><h2 id="\u4E8B\u52A1\u9694\u79BB\u7EA7\u522B" tabindex="-1"><a class="header-anchor" href="#\u4E8B\u52A1\u9694\u79BB\u7EA7\u522B" aria-hidden="true">#</a> \u4E8B\u52A1\u9694\u79BB\u7EA7\u522B</h2><h3 id="\u8BFB\u672A\u63D0\u4EA4" tabindex="-1"><a class="header-anchor" href="#\u8BFB\u672A\u63D0\u4EA4" aria-hidden="true">#</a> \u8BFB\u672A\u63D0\u4EA4</h3><p>\u6700\u4F4E\u7684\u9694\u79BB\u7EA7\u522B\uFF0C\u5141\u8BB8\u8BFB\u53D6\u5C1A\u672A\u63D0\u4EA4\u7684\u6570\u636E\u53D8\u66F4\uFF0C\u53EF\u80FD\u4F1A\u5BFC\u81F4\u810F\u8BFB\u3001\u5E7B\u8BFB\u6216\u4E0D\u53EF\u91CD\u590D\u8BFB\u3002</p><h3 id="\u8BFB\u5DF2\u63D0\u4EA4" tabindex="-1"><a class="header-anchor" href="#\u8BFB\u5DF2\u63D0\u4EA4" aria-hidden="true">#</a> \u8BFB\u5DF2\u63D0\u4EA4</h3><p>\u5141\u8BB8\u8BFB\u53D6\u5E76\u53D1\u4E8B\u52A1\u5DF2\u7ECF\u63D0\u4EA4\u7684\u6570\u636E\uFF0C\u53EF\u4EE5\u963B\u6B62\u810F\u8BFB\uFF0C\u4F46\u662F\u5E7B\u8BFB\u6216\u4E0D\u53EF\u91CD\u590D\u8BFB\u4ECD\u6709\u53EF\u80FD\u53D1\u751F\u3002</p><h3 id="\u53EF\u91CD\u590D\u8BFB" tabindex="-1"><a class="header-anchor" href="#\u53EF\u91CD\u590D\u8BFB" aria-hidden="true">#</a> \u53EF\u91CD\u590D\u8BFB</h3><p>\u5BF9\u540C\u4E00\u5B57\u6BB5\u7684\u591A\u6B21\u8BFB\u53D6\u7ED3\u679C\u90FD\u662F\u4E00\u81F4\u7684\uFF0C\u9664\u975E\u6570\u636E\u662F\u88AB\u672C\u8EAB\u4E8B\u52A1\u81EA\u5DF1\u6240\u4FEE\u6539\uFF0C\u53EF\u4EE5\u963B\u6B62\u810F\u8BFB\u548C\u4E0D\u53EF\u91CD\u590D\u8BFB\uFF0C\u4F46\u5E7B\u8BFB\u4ECD\u6709\u53EF\u80FD\u53D1\u751F\u3002</p><h3 id="\u53EF\u4E32\u884C\u5316" tabindex="-1"><a class="header-anchor" href="#\u53EF\u4E32\u884C\u5316" aria-hidden="true">#</a> \u53EF\u4E32\u884C\u5316</h3><p>\u6700\u9AD8\u7684\u9694\u79BB\u7EA7\u522B\uFF0C\u5B8C\u5168\u670D\u4ECE ACID \u7684\u9694\u79BB\u7EA7\u522B\u3002\u6240\u6709\u7684\u4E8B\u52A1\u4F9D\u6B21\u9010\u4E2A\u6267\u884C\uFF0C\u8FD9\u6837\u4E8B\u52A1\u4E4B\u95F4\u5C31\u5B8C\u5168\u4E0D\u53EF\u80FD\u4EA7\u751F\u5E72\u6270\uFF0C\u4E5F\u5C31\u662F\u8BF4\uFF0C\u8BE5\u7EA7\u522B\u53EF\u4EE5\u9632\u6B62\u810F\u8BFB\u3001\u4E0D\u53EF\u91CD\u590D\u8BFB\u4EE5\u53CA\u5E7B\u8BFB\u3002</p><blockquote><p>MySQL InnoDB \u5B58\u50A8\u5F15\u64CE\u7684\u9ED8\u8BA4\u652F\u6301\u7684\u9694\u79BB\u7EA7\u522B\u662F REPEATABLE-READ\uFF08\u53EF\u91CD\u8BFB\uFF09\u3002</p></blockquote><div class="custom-container tip"><p class="custom-container-title">\u6CE8\u610F</p><p>\u6807\u51C6\u7684 SQL \u9694\u79BB\u7EA7\u522B\u5B9A\u4E49\u91CC\uFF0CREPEATABLE-READ(\u53EF\u91CD\u590D\u8BFB)\u662F\u4E0D\u53EF\u4EE5\u9632\u6B62\u5E7B\u8BFB\u7684\u3002\u4F46\u662FInnoDB \u5B9E\u73B0\u7684 REPEATABLE-READ \u9694\u79BB\u7EA7\u522B\u5176\u5B9E\u662F\u53EF\u4EE5\u89E3\u51B3\u5E7B\u8BFB\u95EE\u9898\u53D1\u751F\u7684\u3002</p><ul><li>\u5FEB\u7167\u8BFB \uFF1A\u7531 MVCC \u673A\u5236\u6765\u4FDD\u8BC1\u4E0D\u51FA\u73B0\u5E7B\u8BFB\u3002</li><li>\u5F53\u524D\u8BFB \uFF1A \u4F7F\u7528 Next-Key Lock \u8FDB\u884C\u52A0\u9501\u6765\u4FDD\u8BC1\u4E0D\u51FA\u73B0\u5E7B\u8BFB\uFF0CNext-Key Lock \u662F\u884C\u9501\uFF08Record Lock\uFF09\u548C\u95F4\u9699\u9501\uFF08Gap Lock\uFF09\u7684\u7ED3\u5408\uFF0C\u884C\u9501\u53EA\u80FD\u9501\u4F4F\u5DF2\u7ECF\u5B58\u5728\u7684\u884C\uFF0C\u4E3A\u4E86\u907F\u514D\u63D2\u5165\u65B0\u884C\uFF0C\u9700\u8981\u4F9D\u8D56\u95F4\u9699\u9501\u3002</li></ul><p>\u56E0\u4E3A\u9694\u79BB\u7EA7\u522B\u8D8A\u4F4E\uFF0C\u4E8B\u52A1\u8BF7\u6C42\u7684\u9501\u8D8A\u5C11\uFF0C\u6240\u4EE5\u5927\u90E8\u5206\u6570\u636E\u5E93\u7CFB\u7EDF\u7684\u9694\u79BB\u7EA7\u522B\u90FD\u662F READ-COMMITTED \uFF0C\u4F46\u662F\u4F60\u8981\u77E5\u9053\u7684\u662F InnoDB \u5B58\u50A8\u5F15\u64CE\u9ED8\u8BA4\u4F7F\u7528 REPEATABLE-READ \u5E76\u4E0D\u4F1A\u6709\u4EFB\u4F55\u6027\u80FD\u635F\u5931\u3002</p><p>InnoDB \u5B58\u50A8\u5F15\u64CE\u5728\u5206\u5E03\u5F0F\u4E8B\u52A1\u7684\u60C5\u51B5\u4E0B\u4E00\u822C\u4F1A\u7528\u5230 SERIALIZABLE \u9694\u79BB\u7EA7\u522B\u3002</p></div><h2 id="\u89E3\u51B3\u5E7B\u8BFB\u7684\u65B9\u6CD5" tabindex="-1"><a class="header-anchor" href="#\u89E3\u51B3\u5E7B\u8BFB\u7684\u65B9\u6CD5" aria-hidden="true">#</a> \u89E3\u51B3\u5E7B\u8BFB\u7684\u65B9\u6CD5</h2><p>\u89E3\u51B3\u5E7B\u8BFB\u7684\u65B9\u5F0F\u6709\u5F88\u591A\uFF0C\u4F46\u662F\u5B83\u4EEC\u7684\u6838\u5FC3\u601D\u60F3\u5C31\u662F\u4E00\u4E2A\u4E8B\u52A1\u5728\u64CD\u4F5C\u67D0\u5F20\u8868\u6570\u636E\u7684\u65F6\u5019\uFF0C\u53E6\u5916\u4E00\u4E2A\u4E8B\u52A1\u4E0D\u5141\u8BB8\u65B0\u589E\u6216\u8005\u5220\u9664\u8FD9\u5F20\u8868\u4E2D\u7684\u6570\u636E\u4E86\u3002\u89E3\u51B3\u5E7B\u8BFB\u7684\u65B9\u5F0F\u4E3B\u8981\u6709\u4EE5\u4E0B\u51E0\u79CD\uFF1A</p><ol><li>\u5C06\u4E8B\u52A1\u9694\u79BB\u7EA7\u522B\u8C03\u6574\u4E3A SERIALIZABLE</li><li>\u5728\u53EF\u91CD\u590D\u8BFB\u7684\u4E8B\u52A1\u7EA7\u522B\u4E0B\uFF0C\u7ED9\u4E8B\u52A1\u64CD\u4F5C\u7684\u8FD9\u5F20\u8868\u6DFB\u52A0\u8868\u9501</li><li>\u5728\u53EF\u91CD\u590D\u8BFB\u7684\u4E8B\u52A1\u7EA7\u522B\u4E0B\uFF0C\u7ED9\u4E8B\u52A1\u64CD\u4F5C\u7684\u8FD9\u5F20\u8868\u6DFB\u52A0 Next-Key Locks</li></ol><blockquote><p>\u53C2\u8003\uFF1A</p><p>https://javaguide.cn/database/mysql/transaction-isolation-level.html#%E5%AE%9E%E9%99%85%E6%83%85%E5%86%B5%E6%BC%94%E7%A4%BA</p><p>\u300AMySQL \u6280\u672F\u5185\u5E55\uFF1AInnoDB \u5B58\u50A8\u5F15\u64CE\u300B</p></blockquote>',39);function d(i,t){return h}var o=e(r,[["render",d]]);export{o as default};
